import{_ as i,a,b as n}from"./chunks/管理端登录界面.yuERlcJ6.js";import{_ as t,o,c as s,a2 as l}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Authentication और Login Device Management","description":"","frontmatter":{},"headers":[],"relativePath":"hi/Safety/authentication-and-login-devices.md","filePath":"hi/Safety/authentication-and-login-devices.md","lastUpdated":1781962217000}'),d={name:"hi/Safety/authentication-and-login-devices.md"};function r(c,e,u,p,h,m){return o(),s("div",null,[...e[0]||(e[0]=[l('<h1 id="authentication-और-login-device-management" tabindex="-1">Authentication और Login Device Management <a class="header-anchor" href="#authentication-और-login-device-management" aria-label="Permalink to &quot;Authentication और Login Device Management&quot;">​</a></h1><p><code>Authentication Management</code> और <code>Login Device Management</code> आपके ImgBed admin panel, public upload entry और WebDAV access को सुरक्षित रखने के लिए हैं।</p><p>इस पेज से आप access credentials सेट कर सकते हैं, कौन-कौन से devices login हैं यह देख सकते हैं, और ज़रूरत पड़ने पर पुराने sessions revoke कर सकते हैं।</p><h2 id="कहाँ-सेट-करें" tabindex="-1">कहाँ सेट करें <a class="header-anchor" href="#कहाँ-सेट-करें" aria-label="Permalink to &quot;कहाँ सेट करें&quot;">​</a></h2><p>Admin panel खोलें, फिर यहाँ जाएँ:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings</span></span></code></pre></div><p>इस पेज में दो मुख्य हिस्से हैं:</p><ul><li>Authentication Management</li><li>Login Device Management</li></ul><p><img src="'+i+'" alt="Authentication management" loading="lazy"></p><h2 id="authentication-management-क्या-करता-है" tabindex="-1">Authentication Management क्या करता है <a class="header-anchor" href="#authentication-management-क्या-करता-है" aria-label="Permalink to &quot;Authentication Management क्या करता है&quot;">​</a></h2><p>Authentication Management access credentials सेव करता है।</p><p>इसके दो प्रकार हैं:</p><ul><li>User-side authentication</li><li>Admin-side authentication</li></ul><h2 id="user-side-authentication" tabindex="-1">User-Side Authentication <a class="header-anchor" href="#user-side-authentication" aria-label="Permalink to &quot;User-Side Authentication&quot;">​</a></h2><p>User-side authentication यानी upload password।</p><p>Upload password सेट करने के बाद सामान्य visitors को upload page इस्तेमाल करने से पहले password डालना होगा। यह तब काम आता है जब आप public upload page को पूरी तरह open नहीं रखना चाहते।</p><p><img src="'+a+'" alt="User login page" loading="lazy"></p><h3 id="upload-password-सेट-करना" tabindex="-1">Upload Password सेट करना <a class="header-anchor" href="#upload-password-सेट-करना" aria-label="Permalink to &quot;Upload Password सेट करना&quot;">​</a></h3><p>Upload password सेट होने पर:</p><ul><li>Visitors को upload page इस्तेमाल करने से पहले password डालना होगा।</li><li>Password सही होने के बाद ही upload उपलब्ध होगा।</li><li>अगर user-side device sessions enabled हैं, तो ImgBed उस user-side device को record करेगा।</li></ul><p>Upload password बदलने पर पुराने user-side sessions invalid हो जाते हैं। Visitors को नया password फिर से डालना होगा।</p><h2 id="admin-side-authentication" tabindex="-1">Admin-Side Authentication <a class="header-anchor" href="#admin-side-authentication" aria-label="Permalink to &quot;Admin-Side Authentication&quot;">​</a></h2><p>Admin-side authentication में admin username और password इस्तेमाल होते हैं।</p><p>यह admin panel की सुरक्षा करता है। Production use के लिए इसे हमेशा configure करना चाहिए।</p><p><img src="'+n+'" alt="Admin login page" loading="lazy"></p><h3 id="admin-credentials-सेट-करना" tabindex="-1">Admin Credentials सेट करना <a class="header-anchor" href="#admin-credentials-सेट-करना" aria-label="Permalink to &quot;Admin Credentials सेट करना&quot;">​</a></h3><p>Admin username और password सेट होने पर:</p><ul><li>Admin panel खोलने के लिए login करना होगा।</li><li>Successful login के बाद एक admin device record बनता है।</li><li>आप Login Device Management में devices review कर सकते हैं, cleanup कर सकते हैं या force offline कर सकते हैं।</li></ul><p>Admin username या password बदलने पर पुराने admin sessions invalid हो जाते हैं। आपको फिर से sign in करना होगा।</p><h2 id="login-device-management-क्या-करता-है" tabindex="-1">Login Device Management क्या करता है <a class="header-anchor" href="#login-device-management-क्या-करता-है" aria-label="Permalink to &quot;Login Device Management क्या करता है&quot;">​</a></h2><p>Login Device Management उन devices को दिखाता है जिन्होंने sign in किया है।</p><p>इससे आप जाँच सकते हैं:</p><ul><li>किन devices ने admin panel access किया।</li><li>किन devices ने user-side upload page access किया।</li><li>कौन से WebDAV clients connect हुए।</li><li>कोई device session अभी valid है या नहीं।</li><li>पुराने devices को force offline करना चाहिए या नहीं।</li></ul><p>इस पेज में तीन tabs हैं:</p><ul><li>Admin</li><li>User</li><li>WebDAV</li></ul><h2 id="global-cookie-security" tabindex="-1">Global Cookie Security <a class="header-anchor" href="#global-cookie-security" aria-label="Permalink to &quot;Global Cookie Security&quot;">​</a></h2><p>Login Device Management के ऊपर global cookie behavior configure किया जा सकता है।</p><h3 id="user-cookie-lifetime" tabindex="-1">User Cookie Lifetime <a class="header-anchor" href="#user-cookie-lifetime" aria-label="Permalink to &quot;User Cookie Lifetime&quot;">​</a></h3><p>यह तय करता है कि user-side login कितने दिनों तक active रह सकता है।</p><p>उदाहरण के लिए, अगर आप इसे 14 days सेट करते हैं, तो visitors को आम तौर पर 14 दिनों तक upload password फिर से डालने की ज़रूरत नहीं होगी।</p><h3 id="admin-cookie-lifetime" tabindex="-1">Admin Cookie Lifetime <a class="header-anchor" href="#admin-cookie-lifetime" aria-label="Permalink to &quot;Admin Cookie Lifetime&quot;">​</a></h3><p>यह तय करता है कि admin login कितने दिनों तक active रह सकता है।</p><p>उदाहरण के लिए, अगर आप इसे 14 days सेट करते हैं, तो administrators को आम तौर पर 14 दिनों तक फिर से sign in नहीं करना पड़ेगा।</p><h3 id="secure-mode" tabindex="-1">Secure Mode <a class="header-anchor" href="#secure-mode" aria-label="Permalink to &quot;Secure Mode&quot;">​</a></h3><p>Secure mode enabled होने पर browser login cookies केवल HTTPS पर भेजता है।</p><p>Production HTTPS sites के लिए इसे enable करें। Local HTTP testing में इसे enable न करें, वरना &quot;login successful है, लेकिन refresh करने पर logout हो जाता है&quot; जैसा व्यवहार दिख सकता है।</p><h2 id="admin-login-devices" tabindex="-1">Admin Login Devices <a class="header-anchor" href="#admin-login-devices" aria-label="Permalink to &quot;Admin Login Devices&quot;">​</a></h2><p>Admin tab उन devices को दिखाता है जिन्होंने admin panel में sign in किया है।</p><p>Device records तभी दिखते हैं जब admin credentials configure हों और admin panel login के ज़रिए access किया गया हो।</p><p>हर device card में यह जानकारी दिख सकती है:</p><ul><li>Device और browser information</li><li>First login IP</li><li>Last active IP</li><li>Login time</li><li>Last active time</li><li>Expiration time</li><li>Current status</li></ul><p>अगर कोई अनजान device दिखे, तो उसे invalid करने के लिए <code>Force Offline</code> इस्तेमाल करें।</p><h2 id="पुराने-devices-cleanup-करना" tabindex="-1">पुराने Devices Cleanup करना <a class="header-anchor" href="#पुराने-devices-cleanup-करना" aria-label="Permalink to &quot;पुराने Devices Cleanup करना&quot;">​</a></h2><p><code>Clean Up Old Devices</code> current tab के पुराने login records को bulk में हटाता है।</p><p>जब आपको लगे कि पुराने sessions दूसरे devices पर अभी भी active हो सकते हैं, तब इसका इस्तेमाल करें।</p><h2 id="force-offline" tabindex="-1">Force Offline <a class="header-anchor" href="#force-offline" aria-label="Permalink to &quot;Force Offline&quot;">​</a></h2><p><code>Force Offline</code> किसी एक device session को invalid करता है।</p><p>Device force offline होने के बाद:</p><ul><li>Admin devices को फिर से sign in करना होगा।</li><li>User-side devices को upload password फिर से डालना होगा।</li><li>WebDAV clients को फिर से authenticate करना होगा।</li></ul><p>Expired या invalid devices को हटाया भी जा सकता है।</p><h2 id="current-device-से-sign-out-करना" tabindex="-1">Current Device से Sign Out करना <a class="header-anchor" href="#current-device-से-sign-out-करना" aria-label="Permalink to &quot;Current Device से Sign Out करना&quot;">​</a></h2><p>Current device card पर <code>Current Device</code> mark लगा होता है।</p><p>Current device से sign out करने के बाद:</p><ul><li>Current admin session sign out हो जाता है।</li><li>Current user-side session sign out हो जाता है।</li></ul><p>उस area को आगे इस्तेमाल करने से पहले आपको फिर से sign in करना होगा।</p>',65)])])}const b=t(d,[["render",r]]);export{f as __pageData,b as default};
